package dev.slne.surf.api.gen.nms

/**
 * Registry of all NMS version configurations.
 *
 * The **reference version** is v26_1 (Paper 26.1+). All other versions are
 * generated by transforming the reference sources.
 *
 * To add a new Minecraft version:
 * 1. Add an [NmsVersionConfig] entry here
 * 2. Create the Gradle module (build.gradle.kts with correct paperweight dev-bundle)
 * 3. Register the module in settings.gradle.kts
 * 4. Re-run the generator: `./gradlew :surf-api-generator:generateNms`
 */
object NmsVersionConfigs {

    /** Reference version identifiers (source of truth). */
    const val REFERENCE_VERSION_ID = "v26_1"
    const val REFERENCE_CLASS_PREFIX = "V26_1"
    const val REFERENCE_MODULE_PATH = "surf-api-paper/surf-api-paper-nms/surf-api-paper-nms-v26-1"

    /**
     * NMS version config for Minecraft 1.21.11 (Canvas).
     *
     * Key differences from 26.1:
     * - `net.minecraft.resources.Identifier` → `net.minecraft.resources.ResourceLocation`
     * - `Identifier.fromNamespaceAndPath(...)` → `ResourceLocation.fromNamespaceAndPath(...)`
     * - `ClientboundClearDialogPacket` does not exist → clearDialogs becomes a no-op
     * - `player.showDialog(...)` does not exist → removed
     * - `noticeDialogWithBuilder` import does not exist → removed
     * - `TypedEntityData` does not exist → use `CustomData.of(...)` instead
     */
    val V1_21_11 = NmsVersionConfig(
        versionId = "v1_21_11",
        classPrefix = "V1_21_11",
        sourceModulePath = "surf-api-paper/surf-api-paper-nms/surf-api-paper-nms-v1-21-11",
        importReplacements = mapOf(
            "import net.minecraft.resources.Identifier" to "import net.minecraft.resources.ResourceLocation",
            "import net.minecraft.world.item.component.TypedEntityData\n" to "",
        ),
        codeReplacements = mapOf(
            // Identifier class → ResourceLocation
            "Identifier.fromNamespaceAndPath(" to "ResourceLocation.fromNamespaceAndPath(",
            // Type references in function signatures
            "id: Identifier" to "id: ResourceLocation",
            "(id: Identifier," to "(id: ResourceLocation,",
            "fun showPacket(id: Identifier," to "fun showPacket(id: ResourceLocation,",
            "fun hidePacket(id: Identifier)" to "fun hidePacket(id: ResourceLocation)",
            "fun createAdvancement(id: Identifier," to "fun createAdvancement(id: ResourceLocation,",
            // TypedEntityData → CustomData.of
            "TypedEntityData.decodeEntity(nbt)" to "CustomData.of(nbt)",
        ),
        fileTransformers = mapOf(
            // The CommonBridge needs special handling for clearDialogs (no dialog support in 1.21.11)
            "dev/slne/surf/api/paper/server/nms/v26_1/bridges/V26_1SurfPaperNmsCommonBridgeImpl.kt" to { content ->
                content
                    // Remove dialog-related imports
                    .replace("import dev.slne.surf.api.paper.dialog.noticeDialogWithBuilder\n", "")
                    .replace("import net.minecraft.network.protocol.common.ClientboundClearDialogPacket\n", "")
                    .replace("import net.kyori.adventure.text.Component\n", "")
                    // Replace clearDialogs implementation with no-op
                    .replace(
                        """    override fun clearDialogs(player: Player, showEmptyDialogBefore: Boolean) {
        if (showEmptyDialogBefore) {
            player.showDialog(noticeDialogWithBuilder(Component.empty()) {})
        }

        player.toNms().connection.send(ClientboundClearDialogPacket.INSTANCE)
    }""",
                        """    override fun clearDialogs(player: Player, showEmptyDialogBefore: Boolean) {
        // Dialogs are not supported in 1.21.11
    }"""
                    )
            },
        ),
    )

    /** All target versions that should be generated from the reference. */
    val ALL_TARGETS = listOf(V1_21_11)
}
